VERAGE_DAILY_SIZE end) / count(*)) / 1073741824 < 0.01 then 0.01 else TRUNC((sum(case when AVERAGE_DAILY_SIZE is null then 0 else AVERAGE_DAILY_SIZE end) / count(*)) / 1073741824, 2) end as averageAllDailySize from ( SELECT * FROM ( SELECT j.*, row_number ( ) over ( PARTITION BY lower(TABLE_PROJECT), upper(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC ) as rnn from table_organization_assets j where STATISTICS_TIME >= trunc(sysdate - #{daysAgo}) and PRIMARY_DATASOURCE_CH != '未知' and SECONDARY_DATASOURCE_CH!= '未知') h
