select primaryDataSourceCh,secondaryDataSourceCh ,primaryOrganizationCh,secondaryOrganizationCh, tableType, tableProject ,name , tableNameEn ,tableAllCount , averageDailyVolume , yesterdayCount ,lifeCycle , valueRate , nullRate ,tableState,statisticsTimeStr,updateType ,frequency,liveType,tableid,registerState,objectId,tableSize,objectState, -- labels, updateDate,updatePeriod,productStage,organizationClassifyCh,dataSourceClassifyCh,exceptionMessage,lifeCycleStatus,resourceId,isStandard from( select rownum rn, PRIMARY_DATASOURCE_CH as primaryDataSourceCh , SECONDARY_DATASOURCE_CH as secondaryDataSourceCh , PRIMARY_ORGANIZATION_CH as primaryOrganizationCh , SECONDARY_ORGANIZATION_CH as secondaryOrganizationCh , case when (SECONDARY_ORGANIZATION_CH is null or SECONDARY_ORGANIZATION_CH = '') and (THREELEVEL_ORGANIZATION_CH is null or THREELEVEL_ORGANIZATION_CH = '') then PRIMARY_ORGANIZATION_CH when THREELEVEL_ORGANIZATION_CH is not null or THREELEVEL_ORGANIZATION_CH !='' then PRIMARY_ORGANIZATION_CH || '->' || THREELEVEL_ORGANIZATION_CH else PRIMARY_ORGANIZATION_CH||'->'||SECONDARY_ORGANIZATION_CH end as organizationClassifyCh, case when SECONDARY_DATASOURCE_CH is null or SECONDARY_DATASOURCE_CH ='' then PRIMARY_DATASOURCE_CH else PRIMARY_DATASOURCE_CH ||'->'|| SECONDARY_DATASOURCE_CH end as dataSourceClassifyCh, case when RES_NAME is null or RES_NAME = '' then TABLE_TYPE||'->'||TABLE_PROJECT else TABLE_TYPE || '->' || RES_NAME || '->' || TABLE_PROJECT end as tableProject, NAME as name , TABLE_NAME_EN as tableNameEn , case when TABLE_ALL_COUNT = '0' then '0' when to_char(TABLE_ALL_COUNT/ 10000, 'fm9999999999990.00')='0.00' then '0' else to_char(TABLE_ALL_COUNT/ 10000, 'fm9999999999990.00') End as tableAllCount, AVERAGE_DAILY_VOLUME as averageDailyVolume, case when YESTERDAY_COUNT = '0' then '0' when to_char(YESTERDAY_COUNT/10000,'fm999999999990.00') = '0.00' then '0' else to_char(YESTERDAY_COUNT/10000,'fm999999999990.00') end as yesterdayCount ,TABLE_TYPE as tableType, LIFE_CYCLE as lifeCycle , VALUE_RATE as valueRate , NULL_RATE as nullRate, TABLE_STATE as tableState,OBJECT_STATE as objectState, case when PARTITION_MESSAGE = 0 then '增量' when PARTITION_MESSAGE = 1 then '全量' else '其它' END as updateType ,to_char(STATISTICS_TIME,'yyyy-MM-dd HH24:mi:ss') as statisticsTimeStr , FREQUENCY as frequency , LIVETYPE as liveType ,SJXJBM as tableid, REGISTER_STATE as registerState, -- CASE WHEN pdi.TABLENAME is not null THEN 2 ELSE 1 END registerState, OBJECT_ID as objectId, case when TABLE_SIZE = '0' then '0' when to_char(TABLE_SIZE/1073741824,'fm999999999990.00000')='0.00000' then '0' else to_char(TABLE_SIZE/1073741824,'fm999999999990.00000') end as tableSize, -- labels, update_date as updateDate,update_period as updatePeriod,'' as productStage, EXCEPTION_MESSAGE as exceptionMessage,LIFE_CYCLE_STATUS as lifeCycleStatus,resourceid,ISSTANDARD as isStandard from ( SELECT * FROM ( SELECT j.*, row_number ( ) over ( PARTITION BY lower(TABLE_TYPE), lower(TABLE_PROJECT), upper(TABLE_NAME_EN) ORDER BY STATISTICS_TIME DESC ) as rnn from table_organization_assets j where STATISTICS_TIME >= trunc(sysdate - #{daysAgo}) )a ) h WHERE h.rnn = 1
and REGISTER_STATE ='2'
and (REGISTER_STATE !='2' or REGISTER_STATE is null)
and (OBJECT_STATE = '1' or OBJECT_STATE = '0')
and (OBJECT_STATE = '-1' or OBJECT_STATE is null)
and
(lower(TABLE_PROJECT) = lower(#{p.secondaryClassifyCh,jdbcType=VARCHAR}) and upper(TABLE_TYPE) = upper(#{p.primaryClassifyCh,jdbcType=VARCHAR}))
and(
(
1=1
and PRIMARY_DATASOURCE_CH = #{sc.primaryClassifyCh,jdbcType=VARCHAR}
and
SECONDARY_DATASOURCE_CH = #{sc.secondaryClassifyCh,jdbcType=VARCHAR}
)
or
(
1=1
and PRIMARY_ORGANIZATION_CH = #{oc.primaryClassifyCh,jdbcType=VARCHAR}
and
SECONDARY_ORGANIZATION_CH = #{oc.secondaryClassifyCh,jdbcType=VARCHAR}
and THREELEVEL_ORGANIZATION_CH = #{oc.threeLevelClassfyCh,jdbcType=VARCHAR}
)
)
and (upper(TABLE_NAME_EN) like upper('%${input}%') or upper(NAME) like upper('%${input}%') or upper(SJXJBM) like upper('%${input}%'))
and
upper(TABLE_NAME_EN) = upper(#{i,jdbcType=VARCHAR})
and to_date(regexp_replace(LASTDATAMODIFIEDTIME, '\..*', ''),'yyyy-MM-dd hh24:mi:ss') >= to_date(#{startLastModifiedTime,jdbcType=VARCHAR},'yyyy-MM-dd')
and to_date(regexp_replace(LASTDATAMODIFIEDTIME, '\..*', ''),'yyyy-MM-dd hh24:mi:ss')-1 <= to_date(#{endLastModifiedTime,jdbcType=VARCHAR},'yyyy-MM-dd')
and TABLE_ALL_COUNT >= #{startRecordNum}
and TABLE_ALL_COUNT <= #{endRecordNum}
and TABLE_SIZE >= #{startStorageSize}
and TABLE_SIZE <= #{endStorageSize}
and upper(TABLE_TYPE)=upper(#{queryTable.tableType,jdbcType=VARCHAR}) and upper(TABLE_PROJECT)=upper(#{queryTable.projectName,jdbcType=VARCHAR}) and upper(TABLE_NAME_EN)=upper(#{queryTable.tableName,jdbcType=VARCHAR})
)
objectState in
#{item}
and productStage in
#{item}
and registerState in
#{item}
and tableProject in
#{item}
and isStandard in
#{item}
and tableState in
#{item}
and
tableid is null
tableid is not null
and updatePeriod in
#{item}
order by case when registerState = 2 then 1 when registerState = -1 then 2 when registerState = 1 then 3 when registerState is null then 4 end,lifeCycleStatus,rn desc

mapper.update:
BEGIN

    update TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.registerState}
    where UPPER(table_name_en) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})

        and UPPER(sjxjbm) = UPPER(#{item.tableid,jdbcType=VARCHAR})

    ;
    update DATA_REGISTER
    set APPROVAL_STATUS = '1',
    APPROVAL_UPDATE_TIME = to_char(sysdate , 'yyyy-MM-dd hh24:mi:ss')
    where TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR};

END;

BEGIN

    update TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.registerState}
    where UPPER(table_name_en) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})

        and UPPER(sjxjbm) = UPPER(#{item.tableid,jdbcType=VARCHAR})

    ;
    update DATA_REGISTER
    set APPROVAL_STATUS = '4',
    APPROVAL_UPDATE_TIME = to_char(sysdate , 'yyyy-MM-dd hh24:mi:ss')
    where TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR};

END;

BEGIN

    update TABLE_ORGANIZATION_ASSETS set REGISTER_STATE = #{item.TYPE,jdbcType=VARCHAR}
    where UPPER(SJXJBM) = UPPER(#{item.TABLEID,jdbcType=VARCHAR});

END;

BEGIN

    update TABLE_ORGANIZATION_ASSETS set OBJECT_STATE = #{state,jdbcType=VARCHAR}
    where UPPER(SJXJBM) = UPPER(#{item,jdbcType=VARCHAR})


    update SYNLTE."OBJECT" set OBJECTSTATE = #{state,jdbcType=VARCHAR}
    where UPPER(TABLEID) = UPPER(#{item,jdbcType=VARCHAR})

END;

BEGIN merge into DATA_REGISTER a using (select #{item.approvalType,jdbcType=VARCHAR} as approvalType,
#{item.tableNameEn,jdbcType=VARCHAR} as tableNameEn, #{item.tableProject,jdbcType=VARCHAR} as tableProject from dual) b on (a.TABLE_NAME_EN = b.tableNameEn and a.TABLE_PROJECT = b.tableProject
#{item.tableId,jdbcType=VARCHAR} as SJXJBM from dual) b on (a.SJXJBM = b.SJXJBM
and a.APPROVAL_TYPE = b.approvalType) when matched then update set APPROVAL_ID = #{item.approvalId,jdbcType=VARCHAR}, APPROVAL_STATUS = #{item.approvalStatus,jdbcType=VARCHAR}, APPROVAL_UPDATE_TIME = to_char(sysdate , 'yyyy-MM-dd hh24:mi:ss') when not matched then insert (SJXJBM,TABLE_NAME_EN,OBJECT_ID,APPROVAL_ID,APPROVAL_STATUS,APPROVAL_CREATE_TIME, APPROVAL_UPDATE_TIME,APPROVAL_TYPE,TABLE_PROJECT) values(#{item.tableId,jdbcType=VARCHAR},#{item.tableNameEn,jdbcType=VARCHAR},#{item.objectId,jdbcType=VARCHAR}, #{item.approvalId,jdbcType=VARCHAR},#{item.approvalStatus,jdbcType=VARCHAR},to_char(sysdate , 'yyyy-MM-dd hh24:mi:ss'), to_char(sysdate , 'yyyy-MM-dd hh24:mi:ss'),#{item.approvalType,jdbcType=VARCHAR}, #{item.tableProject,jdbcType=VARCHAR}); update TABLE_ORGANIZATION_ASSETS set
REGISTER_STATE = #{item.approvalStatus,jdbcType=VARCHAR} where UPPER(SJXJBM) = UPPER(#{item.tableId,jdbcType=VARCHAR})
LIFE_CYCLE_STATUS = #{item.approvalStatus,jdbcType=VARCHAR} where UPPER(TABLE_NAME_EN) = UPPER(#{item.tableNameEn,jdbcType=VARCHAR})
and TABLE_TYPE = #{itm,jdbcType=VARCHAR}
and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}
; END;

mapper.select:
select SJXJBM as tableId,TABLE_NAME_EN as tableNameEn,OBJECT_ID as objectId,APPROVAL_ID as approvalId,
APPROVAL_STATUS as approvalStatus,APPROVAL_CREATE_TIME as approvalCreateTime,APPROVAL_UPDATE_TIME as
approvalUpdateTime,TABLE_PROJECT as tableProject,APPROVAL_TYPE as approvalType
from DATA_REGISTER where APPROVAL_STATUS = '2'


        and SJXJBM = #{item.tableId,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{item.tableProject,jdbcType=VARCHAR}
        and TABLE_NAME_EN = #{item.tableNameEn,jdbcType=VARCHAR}

mapper.update:
BEGIN
update DATA_REGISTER
set APPROVAL_STATUS = '1'
where TABLE_PROJECT = #{requestParam.tableProject,jdbcType=VARCHAR}
and TABLE_NAME_EN = #{requestParam.tableNameEn,jdbcType=VARCHAR}
and APPROVAL_TYPE = 'updateLifeCycle';
update TABLE_ORGANIZATION_ASSETS
set LIFE_CYCLE_STATUS = '1',
LIFE_CYCLE = #{requestParam.value,jdbcType=VARCHAR}
where
STATISTICS_TIME >= trunc(sysdate) and
UPPER(TABLE_NAME_EN) = UPPER(#{requestParam.tableNameEn,jdbcType=VARCHAR})


        and TABLE_TYPE = #{itm,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}


;
end;

BEGIN
update DATA_REGISTER
set APPROVAL_STATUS = '4'
where TABLE_PROJECT = #{requestParam.tableProject,jdbcType=VARCHAR}
and TABLE_NAME_EN = #{requestParam.tableNameEn,jdbcType=VARCHAR}
and APPROVAL_TYPE = 'updateLifeCycle';
update TABLE_ORGANIZATION_ASSETS set LIFE_CYCLE_STATUS = '4'
where
STATISTICS_TIME >= trunc(sysdate) and
UPPER(TABLE_NAME_EN) = UPPER(#{requestParam.tableNameEn,jdbcType=VARCHAR})


        and TABLE_TYPE = #{itm,jdbcType=VARCHAR}


        and TABLE_PROJECT = #{itm,jdbcType=VARCHAR}


;
end;

